SELECT COALESCE(
    (
        SELECT product_id
        FROM order_items
        WHERE order_item_id = #{order_item_id}
    ),
    0
)

SELECT COUNT(*)
FROM point_history
WHERE user_id = #{user_id}
AND order_item_id = #{order_item_id}
AND type = 'EARN'

SELECT COALESCE(
    (
        SELECT point_balance
        FROM user_points
        WHERE user_id = #{user_id}
    ),
    0
)

mapper.update:
UPDATE user_points
SET point_balance = point_balance - #{point_amount},
    updated_at = CURRENT_TIMESTAMP
WHERE user_id = #{user_id}
AND point_balance >= #{point_amount}

mapper.select:
SELECT COALESCE(SUM(point_amount), 0)
FROM point_history
WHERE user_id = #{user_id}
AND order_id = #{order_id}
AND type = 'USE'

SELECT COUNT(*)
FROM point_history
WHERE user_id = #{user_id}
AND order_id = #{order_id}
AND type = 'REFUND'

