UPDATE user_coupons
SET used_yn = 'Y',
    used_at = CURRENT_TIMESTAMP
WHERE user_coupon_id = #{user_coupon_id}
AND user_id = #{user_id}
AND used_yn = 'N'

UPDATE user_coupons
SET used_yn = 'N',
    used_at = NULL
WHERE user_coupon_id = #{user_coupon_id}
AND user_id = #{user_id}
AND used_yn = 'Y'
